/**
 * GET /api/admin/qr-pdf
 *
 * Generates an A4 PDF with a 3×5 grid of QR codes — one per table.
 * Each QR encodes http://SHOP_IP:SHOP_PORT/order?table=N.
 * Protected by admin cookie auth.
 */

import { NextRequest } from "next/server";
import path from "path";
import PDFDocument from "pdfkit";
import QRCode from "qrcode";

import { checkAdminCookie } from "@/lib/auth";

// Force Node.js runtime — pdfkit uses Buffer/fs internally
export const runtime = "nodejs";

export async function GET(request: NextRequest) {
  // ── Auth gate ──────────────────────────────────────────────
  const cookieHeader = request.headers.get("cookie");
  if (!checkAdminCookie(cookieHeader)) {
    return Response.json({ error: "Unauthorized" }, { status: 401 });
  }

  // ── Env var validation ─────────────────────────────────────
  const shopIp = process.env.SHOP_IP;
  if (!shopIp) {
    return Response.json(
      { error: "SHOP_IP chưa được cấu hình" },
      { status: 400 },
    );
  }
  const shopPort = process.env.SHOP_PORT || "3000";
  const tableCount = Math.max(0, parseInt(process.env.TABLE_COUNT || "15", 10));

  if (tableCount === 0) {
    return Response.json(
      { error: "TABLE_COUNT phải lớn hơn 0" },
      { status: 400 },
    );
  }

  // ── Font validation ────────────────────────────────────────
  const fontPath = path.join(process.cwd(), "public", "fonts", "Inter.ttf");
  try {
    const fs = await import("fs");
    if (!fs.existsSync(fontPath)) {
      return Response.json(
        { error: "Font file not found" },
        { status: 500 },
      );
    }
  } catch {
    return Response.json(
      { error: "Font file not found" },
      { status: 500 },
    );
  }

  try {
    // ── Generate QR buffers ────────────────────────────────────
    const qrBuffers: Buffer[] = [];
    for (let n = 1; n <= tableCount; n++) {
      const url = `http://${shopIp}:${shopPort}/order?table=${n}`;
      const buf = await QRCode.toBuffer(url, {
        width: 300,
        errorCorrectionLevel: "M",
      });
      qrBuffers.push(buf);
    }

    // ── Build PDF ──────────────────────────────────────────────
    // A4: 595.28 × 841.89 pt, margin 40
    const doc = new PDFDocument({ size: "A4", margin: 40 });
    doc.registerFont("Vietnamese", fontPath);

    // Collect PDF chunks (cannot pipe to Response in Next.js)
    const chunks: Buffer[] = [];
    doc.on("data", (chunk: Buffer) => chunks.push(chunk));
    const pdfReady = new Promise<void>((resolve, reject) => {
      doc.on("end", resolve);
      doc.on("error", reject);
    });

    // ── Layout constants ─────────────────────────────────────
    const pageWidth = 595.28;
    const margin = 40;
    const cols = 3;
    const rows = 5;
    const perPage = cols * rows;
    const availableWidth = pageWidth - margin * 2;
    const colWidth = availableWidth / cols;
    const qrSize = 120;
    const rowHeight = 150;
    const titleHeight = 50;

    // ── Render pages ─────────────────────────────────────────
    const totalPages = Math.ceil(tableCount / perPage);

    for (let page = 0; page < totalPages; page++) {
      if (page > 0) doc.addPage();

      // Page title (only first page gets big title)
      if (page === 0) {
        doc
          .font("Vietnamese")
          .fontSize(20)
          .fillColor("#000000")
          .text("QR Code - TraSua", margin, margin, {
            align: "center",
            width: availableWidth,
          });
      }

      const startY = page === 0 ? margin + titleHeight : margin;
      const startIdx = page * perPage;
      const endIdx = Math.min(startIdx + perPage, tableCount);

      for (let i = startIdx; i < endIdx; i++) {
        const localIdx = i - startIdx;
        const col = localIdx % cols;
        const row = Math.floor(localIdx / cols);

        const cellX = margin + col * colWidth;
        const cellY = startY + row * rowHeight;

        // Center QR in column
        const qrX = cellX + (colWidth - qrSize) / 2;

        // Embed QR image
        doc.image(qrBuffers[i], qrX, cellY, {
          width: qrSize,
          height: qrSize,
        });

        // "Bàn N" label — 14pt, centered below QR
        doc
          .font("Vietnamese")
          .fontSize(14)
          .fillColor("#1a1a1a")
          .text(`Bàn ${i + 1}`, cellX, cellY + qrSize + 4, {
            width: colWidth,
            align: "center",
          });

        // "Quét để đặt món" subtitle — 10pt, lighter
        doc
          .font("Vietnamese")
          .fontSize(10)
          .fillColor("#666666")
          .text("Quét để đặt món", cellX, cellY + qrSize + 20, {
            width: colWidth,
            align: "center",
          });
      }
    }

    doc.end();
    await pdfReady;

    const pdfBuffer = Buffer.concat(chunks);

    return new Response(pdfBuffer, {
      status: 200,
      headers: {
        "Content-Type": "application/pdf",
        "Content-Disposition": 'attachment; filename="trasua-qr-codes.pdf"',
        "Cache-Control": "no-store",
      },
    });
  } catch (err) {
    console.error("[qr-pdf] PDF generation failed:", err);
    return Response.json(
      { error: "PDF generation failed" },
      { status: 500 },
    );
  }
}

'use client'

import { usePathname } from 'next/navigation'
import Link from 'next/link'

// ─── Navigation Config ──────────────────────────────────────────────

const NAV_ITEMS = [
  { href: '/admin/menu', label: 'Thực đơn', emoji: '📋' },
  { href: '/admin/tables', label: 'Bàn', emoji: '🪑' },
  { href: '/admin/qr', label: 'QR Code', emoji: '📱' },
] as const

// ─── Admin Navigation ───────────────────────────────────────────────

export default function AdminNav() {
  const pathname = usePathname()

  return (
    <nav
      className="fixed bottom-0 left-0 right-0 z-50 bg-white/80 backdrop-blur-xl border-t border-amber-200/60 shadow-[0_-2px_16px_rgba(180,120,40,0.08)]"
      aria-label="Điều hướng quản trị"
    >
      <div className="max-w-7xl mx-auto flex items-stretch justify-around">
        {NAV_ITEMS.map(({ href, label, emoji }) => {
          const isActive = pathname.startsWith(href)

          return (
            <Link
              key={href}
              href={href}
              className={`
                relative flex flex-col items-center justify-center gap-1
                min-h-[56px] min-w-[72px] px-4 py-2
                text-xs font-semibold tracking-wide
                transition-all duration-200 ease-out
                ${
                  isActive
                    ? 'text-amber-900'
                    : 'text-amber-600/60 hover:text-amber-800 active:scale-95'
                }
              `}
              aria-current={isActive ? 'page' : undefined}
            >
              {/* Active indicator pill */}
              {isActive && (
                <span
                  className="absolute top-0 left-1/2 -translate-x-1/2 w-10 h-[3px] rounded-full bg-amber-500"
                  aria-hidden="true"
                />
              )}

              <span className="text-xl leading-none" aria-hidden="true">
                {emoji}
              </span>
              <span>{label}</span>
            </Link>
          )
        })}

        {/* Logout link */}
        <Link
          href="/admin/login"
          className="
            relative flex flex-col items-center justify-center gap-1
            min-h-[56px] min-w-[72px] px-4 py-2
            text-xs font-semibold tracking-wide
            text-amber-600/60 hover:text-red-600 active:scale-95
            transition-all duration-200 ease-out
          "
        >
          <span className="text-xl leading-none" aria-hidden="true">🚪</span>
          <span>Đăng xuất</span>
        </Link>
      </div>
    </nav>
  )
}

import { describe, it, expect, vi, beforeEach } from 'vitest'

// ─── Mock Prisma ────────────────────────────────────────────────────
const mockFindMany = vi.fn()
const mockCreate = vi.fn()
const mockFindUnique = vi.fn()
const mockUpdate = vi.fn()

vi.mock('@/lib/prisma', () => ({
  prisma: {
    menuItem: {
      findMany: (...args: unknown[]) => mockFindMany(...args),
      create: (...args: unknown[]) => mockCreate(...args),
      findUnique: (...args: unknown[]) => mockFindUnique(...args),
      update: (...args: unknown[]) => mockUpdate(...args),
    },
  },
}))

// ─── Import route handlers (after mock is set up) ───────────────────
import { GET, POST } from '../route'
import { PUT, PATCH, DELETE } from '../[id]/route'

// ─── Helpers ────────────────────────────────────────────────────────

/** Create a NextRequest with JSON body */
function makeRequest(
  url: string,
  method: string,
  body?: Record<string, unknown>,
): Request {
  const init: RequestInit = {
    method,
    headers: { 'content-type': 'application/json' },
  }
  if (body) init.body = JSON.stringify(body)
  return new Request(url, init)
}

/** Build the context object Next.js passes to dynamic route handlers */
function makeContext(id: string | number) {
  return { params: Promise.resolve({ id: String(id) }) }
}

/** Parse JSON from a NextResponse */
async function json(res: Response) {
  return res.json()
}

// ─── Reset mocks ────────────────────────────────────────────────────
beforeEach(() => {
  vi.clearAllMocks()
})

// =====================================================================
// GET /api/admin/menu
// =====================================================================
describe('GET /api/admin/menu', () => {
  it('returns all items including hidden ones', async () => {
    const items = [
      { id: 1, name: 'Trà sữa', hidden: false, available: true },
      { id: 2, name: 'Cà phê', hidden: true, available: true },
    ]
    mockFindMany.mockResolvedValue(items)

    const res = await GET()
    expect(res.status).toBe(200)

    const data = await json(res)
    expect(data.items).toHaveLength(2)
    expect(data.items[1].hidden).toBe(true)

    // Verify findMany was called without hidden filter
    expect(mockFindMany).toHaveBeenCalledWith({
      orderBy: { sortOrder: 'asc' },
    })
  })

  it('returns 500 on database error', async () => {
    mockFindMany.mockRejectedValue(new Error('DB connection failed'))

    const res = await GET()
    expect(res.status).toBe(500)

    const data = await json(res)
    expect(data.error).toBeDefined()
  })
})

// =====================================================================
// POST /api/admin/menu
// =====================================================================
describe('POST /api/admin/menu', () => {
  it('creates item with valid data', async () => {
    const newItem = {
      id: 10,
      name: 'Trà đào',
      price: 35000,
      category: 'DRINK',
      description: null,
      sortOrder: 0,
      available: true,
      hidden: false,
    }
    mockCreate.mockResolvedValue(newItem)

    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: 'Trà đào',
      price: 35000,
      category: 'DRINK',
    })

    const res = await POST(req as any)
    expect(res.status).toBe(201)

    const data = await json(res)
    expect(data.item.name).toBe('Trà đào')
    expect(data.item.price).toBe(35000)

    expect(mockCreate).toHaveBeenCalledOnce()
    const createArg = mockCreate.mock.calls[0][0]
    expect(createArg.data.name).toBe('Trà đào')
    expect(createArg.data.price).toBe(35000)
    expect(createArg.data.category).toBe('DRINK')
  })

  it('returns 400 for missing name', async () => {
    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      price: 35000,
      category: 'DRINK',
    })

    const res = await POST(req as any)
    expect(res.status).toBe(400)

    const data = await json(res)
    expect(data.error).toContain('Tên món')
  })

  it('returns 400 for empty name', async () => {
    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: '   ',
      price: 35000,
      category: 'DRINK',
    })

    const res = await POST(req as any)
    expect(res.status).toBe(400)

    const data = await json(res)
    expect(data.error).toContain('Tên món')
  })

  it('returns 400 for price <= 0', async () => {
    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: 'Trà đào',
      price: 0,
      category: 'DRINK',
    })

    const res = await POST(req as any)
    expect(res.status).toBe(400)

    const data = await json(res)
    expect(data.error).toContain('Giá')
  })

  it('returns 400 for negative price', async () => {
    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: 'Trà đào',
      price: -5000,
      category: 'DRINK',
    })

    const res = await POST(req as any)
    expect(res.status).toBe(400)
  })

  it('returns 400 for non-integer price', async () => {
    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: 'Trà đào',
      price: 35.5,
      category: 'DRINK',
    })

    const res = await POST(req as any)
    expect(res.status).toBe(400)
  })

  it('returns 400 for invalid category', async () => {
    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: 'Trà đào',
      price: 35000,
      category: 'DESSERT',
    })

    const res = await POST(req as any)
    expect(res.status).toBe(400)

    const data = await json(res)
    expect(data.error).toContain('DRINK')
  })

  it('returns 400 for invalid JSON body', async () => {
    const req = new Request('http://localhost/api/admin/menu', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: 'not json',
    })

    const res = await POST(req as any)
    expect(res.status).toBe(400)
  })

  it('trims whitespace from name', async () => {
    mockCreate.mockResolvedValue({
      id: 11,
      name: 'Trà đào',
      price: 35000,
      category: 'DRINK',
    })

    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: '  Trà đào  ',
      price: 35000,
      category: 'DRINK',
    })

    await POST(req as any)

    const createArg = mockCreate.mock.calls[0][0]
    expect(createArg.data.name).toBe('Trà đào')
  })

  it('sets default available=true and sortOrder=0', async () => {
    mockCreate.mockResolvedValue({ id: 12, name: 'Test' })

    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: 'Test',
      price: 10000,
      category: 'FOOD',
    })

    await POST(req as any)

    const createArg = mockCreate.mock.calls[0][0]
    expect(createArg.data.available).toBe(true)
    expect(createArg.data.sortOrder).toBe(0)
  })

  it('accepts optional description', async () => {
    mockCreate.mockResolvedValue({ id: 13, name: 'Test', description: 'Ngon lắm' })

    const req = makeRequest('http://localhost/api/admin/menu', 'POST', {
      name: 'Test',
      price: 10000,
      category: 'FOOD',
      description: 'Ngon lắm',
    })

    await POST(req as any)

    const createArg = mockCreate.mock.calls[0][0]
    expect(createArg.data.description).toBe('Ngon lắm')
  })
})

// =====================================================================
// PUT /api/admin/menu/[id]
// =====================================================================
describe('PUT /api/admin/menu/[id]', () => {
  it('updates fields for an existing item', async () => {
    mockFindUnique.mockResolvedValue({ id: 1, name: 'Old Name' })
    mockUpdate.mockResolvedValue({
      id: 1,
      name: 'New Name',
      price: 40000,
    })

    const req = makeRequest('http://localhost/api/admin/menu/1', 'PUT', {
      name: 'New Name',
      price: 40000,
    })

    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(200)

    const data = await json(res)
    expect(data.item.name).toBe('New Name')
    expect(data.item.price).toBe(40000)
  })

  it('returns 404 for non-existent ID', async () => {
    mockFindUnique.mockResolvedValue(null)

    const req = makeRequest('http://localhost/api/admin/menu/999', 'PUT', {
      name: 'New Name',
    })

    const res = await PUT(req as any, makeContext(999))
    expect(res.status).toBe(404)

    const data = await json(res)
    expect(data.error).toContain('không tồn tại')
  })

  it('returns 400 for invalid ID (NaN)', async () => {
    const req = makeRequest('http://localhost/api/admin/menu/abc', 'PUT', {
      name: 'New Name',
    })

    const res = await PUT(req as any, makeContext('abc'))
    expect(res.status).toBe(400)
  })

  it('returns 400 for empty name', async () => {
    mockFindUnique.mockResolvedValue({ id: 1, name: 'Existing' })

    const req = makeRequest('http://localhost/api/admin/menu/1', 'PUT', {
      name: '',
    })

    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })

  it('returns 400 for price <= 0', async () => {
    mockFindUnique.mockResolvedValue({ id: 1, name: 'Existing' })

    const req = makeRequest('http://localhost/api/admin/menu/1', 'PUT', {
      price: 0,
    })

    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })

  it('returns 400 for invalid category', async () => {
    mockFindUnique.mockResolvedValue({ id: 1, name: 'Existing' })

    const req = makeRequest('http://localhost/api/admin/menu/1', 'PUT', {
      category: 'INVALID',
    })

    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })

  it('returns 400 for invalid JSON body', async () => {
    const req = new Request('http://localhost/api/admin/menu/1', {
      method: 'PUT',
      headers: { 'content-type': 'application/json' },
      body: 'not json',
    })

    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })

  it('validates sortOrder is an integer', async () => {
    mockFindUnique.mockResolvedValue({ id: 1, name: 'Existing' })

    const req = makeRequest('http://localhost/api/admin/menu/1', 'PUT', {
      sortOrder: 2.5,
    })

    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })

  it('validates available is boolean', async () => {
    mockFindUnique.mockResolvedValue({ id: 1, name: 'Existing' })

    const req = makeRequest('http://localhost/api/admin/menu/1', 'PUT', {
      available: 'yes',
    })

    const res = await PUT(req as any, makeContext(1))
    expect(res.status).toBe(400)
  })
})

