    return NextResponse.json(
      { error: 'Không thể tải thông tin bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * PUT /api/admin/tables/[id]
 *
 * Renames a table.
 * Body: { name: string }
 */
export async function PUT(request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json({ error: 'Dữ liệu không hợp lệ.' }, { status: 400 })
  }

  const { name } = body

  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return NextResponse.json({ error: 'Tên bàn không được để trống.' }, { status: 400 })
  }

  const trimmedName = name.trim()
  if (trimmedName.length > 50) {
    return NextResponse.json({ error: 'Tên bàn không được quá 50 ký tự.' }, { status: 400 })
  }

  try {
    const existing = await prisma.table.findUnique({ where: { id } })
    if (!existing) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    const table = await prisma.table.update({
      where: { id },
      data: { name: trimmedName },
    })

    console.log(`[PUT /api/admin/tables/${id}] Renamed to: ${table.name}`)

    return NextResponse.json({
      id: table.id,
      number: table.number,
      name: table.name,
      orderCount: existing.orders?.length ?? 0,
    })
  } catch (error) {
    console.error(`[PUT /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể cập nhật bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * DELETE /api/admin/tables/[id]
 *
 * Deletes a table only if it has no unpaid orders.
 * Guard: checks for orders with status NOT IN ['PAID', 'CANCELLED'].
 */
export async function DELETE(_request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  try {
    const table = await prisma.table.findUnique({ where: { id } })
    if (!table) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    // Deletion guard: check for unpaid orders
    const unpaidOrder = await prisma.order.findFirst({
      where: { tableId: id, status: { notIn: ['PAID', 'CANCELLED'] } },
    })

    if (unpaidOrder) {
      console.log(`[DELETE /api/admin/tables/${id}] Guard triggered: unpaid orders exist`)
      return NextResponse.json(
        { error: 'Bàn đang có đơn chưa thanh toán, không thể xoá.' },
        { status: 409 },
      )
    }

    await prisma.table.delete({ where: { id } })

    console.log(`[DELETE /api/admin/tables/${id}] Deleted table: ${table.name}`)

    return new NextResponse(null, { status: 204 })
  } catch (error) {
    console.error(`[DELETE /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể xoá bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

